-- FAQItem (8)
INSERT OR REPLACE INTO FAQItem (id,question,answer,sort_order,is_active,created_date,updated_date) VALUES ('6a2f90b4f4b9cfa834d1a417','Can you match an existing cabinet style or finish?','Yes, we can match existing cabinet styles and finishes, subject to material availability. Bring us a sample or photo and we''ll do our best to create a seamless match for your new pieces.',4,1,'2026-06-15T05:42:12.080000','2026-06-15T05:42:12.080000');
INSERT OR REPLACE INTO FAQItem (id,question,answer,sort_order,is_active,created_date,updated_date) VALUES ('6a2f90b4f4b9cfa834d1a41b','Who is my point of contact throughout the project?','During the design phase, your assigned designer is your primary contact. From the engineering phase through project completion, your Project Coordinator takes the lead. You''ll always know who to reach and they''ll be responsive to your questions.',8,1,'2026-06-15T05:42:12.080000','2026-06-15T05:42:12.080000');
INSERT OR REPLACE INTO FAQItem (id,question,answer,sort_order,is_active,created_date,updated_date) VALUES ('6a2f90b4f4b9cfa834d1a416','What types of wood and finishes do you offer?','We work with a wide range of premium materials including maple, walnut, oak, rift-cut white oak, and select exotic veneers. Finish options include paint (any color, including custom color matching), stain, glaze, and combination finishes. We''ll bring samples to your consultation so you can see and feel the options.',3,1,'2026-06-15T05:42:12.080000','2026-06-15T05:42:12.080000');
INSERT OR REPLACE INTO FAQItem (id,question,answer,sort_order,is_active,created_date,updated_date) VALUES ('6a2f90b4f4b9cfa834d1a41a','What are your payment methods?','We accept checks payable to Dream Home Design LLC, ACH/bank transfers, and Zelle. We also accept credit cards with a 3% processing fee. Your office manager, Bojana Sabic, will guide you through payment options during onboarding.',7,1,'2026-06-15T05:42:12.080000','2026-06-15T05:42:12.080000');
INSERT OR REPLACE INTO FAQItem (id,question,answer,sort_order,is_active,created_date,updated_date) VALUES ('6a2f90b4f4b9cfa834d1a415','Can I make changes after the initial design?','Yes! We welcome revisions during the design phase — it''s part of the process. However, once drawings are signed off and production begins, any changes require a formal change order which may affect timeline and cost. Your designer will walk you through this process.',2,1,'2026-06-15T05:42:12.080000','2026-06-15T05:42:12.080000');
INSERT OR REPLACE INTO FAQItem (id,question,answer,sort_order,is_active,created_date,updated_date) VALUES ('6a2f90b4f4b9cfa834d1a419','Do you handle electrical, plumbing, or structural work?','We do not perform electrical, plumbing, or structural work directly. However, we partner with trusted specialists in each area and can coordinate these services as part of your project. These contractors are engaged separately but work closely with our team.',6,1,'2026-06-15T05:42:12.080000','2026-06-15T05:42:12.080000');
INSERT OR REPLACE INTO FAQItem (id,question,answer,sort_order,is_active,created_date,updated_date) VALUES ('6a2f90b4f4b9cfa834d1a418','What if I need more than just cabinets?','We offer full interior design services in addition to custom cabinetry. Our design team can help with space planning, material selection, color consultation, and overall design direction for an additional fee. Many clients find that a holistic approach delivers the best results.',5,1,'2026-06-15T05:42:12.080000','2026-06-15T05:42:12.080000');
INSERT OR REPLACE INTO FAQItem (id,question,answer,sort_order,is_active,created_date,updated_date) VALUES ('6a2f90b4f4b9cfa834d1a414','How long will my project take?','Most projects complete in 12–18 weeks from design sign-off to installation. This includes 6–8 weeks of manufacturing, 1–2 weeks for shipping, and 1–4 weeks for installation. Complex projects may take longer. Your project coordinator will provide a detailed timeline at the start.',1,1,'2026-06-15T05:42:12.080000','2026-06-15T05:42:12.080000');

-- ProcessStage (8)
INSERT OR REPLACE INTO ProcessStage (id,stage_number,title,description,is_active,created_date,updated_date) VALUES ('6a2f90b4f4b9cfa834d1a40e',3,'Pricing Proposal & Agreement','We present a comprehensive quote with full transparency on every line item. Once you''re satisfied, we formalize the agreement and collect the production deposit to move forward.',1,'2026-06-15T05:42:12.074000','2026-06-15T05:42:12.074000');
INSERT OR REPLACE INTO ProcessStage (id,stage_number,title,description,is_active,created_date,updated_date) VALUES ('6a2f90b4f4b9cfa834d1a412',7,'Installation (1–4 weeks)','Our experienced installation team unloads, stages, and preps the site. Cabinets are installed systematically — boxes first, then doors, drawers, and trim. On-site touch-ups, caulking, and final cleaning ensure a flawless result.',1,'2026-06-15T05:42:12.074000','2026-06-15T05:42:12.074000');
INSERT OR REPLACE INTO ProcessStage (id,stage_number,title,description,is_active,created_date,updated_date) VALUES ('6a2f90b4f4b9cfa834d1a413',8,'Project Sign-Off & Final Invoice','We conduct a thorough walkthrough with you and/or your builder. Any punch list items are addressed, care instructions are provided, and the final invoice is processed. Your dream space is complete.',1,'2026-06-15T05:42:12.074000','2026-06-15T05:42:12.074000');
INSERT OR REPLACE INTO ProcessStage (id,stage_number,title,description,is_active,created_date,updated_date) VALUES ('6a2f90b4f4b9cfa834d1a40d',2,'Design Development','Your dedicated designer leads an in-depth design consultation. We create detailed drawings, 3D renderings, and material boards. Together we refine every detail — door styles, finishes, paint samples, hardware — until it''s exactly right.',1,'2026-06-15T05:42:12.074000','2026-06-15T05:42:12.074000');
INSERT OR REPLACE INTO ProcessStage (id,stage_number,title,description,is_active,created_date,updated_date) VALUES ('6a2f90b4f4b9cfa834d1a411',6,'Shipping & Delivery (1–2 weeks)','Our logistics team coordinates loading, transportation, and delivery to your job site. Every piece is accounted for and handled with care.',1,'2026-06-15T05:42:12.074000','2026-06-15T05:42:12.074000');
INSERT OR REPLACE INTO ProcessStage (id,stage_number,title,description,is_active,created_date,updated_date) VALUES ('6a2f90b4f4b9cfa834d1a40c',1,'Sales Contact & Initial Consultation','We begin with a conversation about your goals, lifestyle, and vision. Visit our showroom to see and touch our materials firsthand. You''ll receive a preliminary estimate, and a 5–10% retainer secures your place in our design queue.',1,'2026-06-15T05:42:12.074000','2026-06-15T05:42:12.074000');
INSERT OR REPLACE INTO ProcessStage (id,stage_number,title,description,is_active,created_date,updated_date) VALUES ('6a2f90b4f4b9cfa834d1a40f',4,'Engineering & Production Planning','Our engineering team translates your design into precise shop drawings, CNC programming, and a complete bill of materials. Production is scheduled and work orders are generated.',1,'2026-06-15T05:42:12.074000','2026-06-15T05:42:12.074000');
INSERT OR REPLACE INTO ProcessStage (id,stage_number,title,description,is_active,created_date,updated_date) VALUES ('6a2f90b4f4b9cfa834d1a410',5,'Manufacturing (6–8 weeks)','Your cabinetry comes to life in our Arizona production facility. Material preparation, finishing, CNC panel cutting, edgebanding, assembly, hardware installation — each piece undergoes final inspection and is carefully packaged.',1,'2026-06-15T05:42:12.074000','2026-06-15T05:42:12.074000');

-- InvestmentTier (3)
INSERT OR REPLACE INTO InvestmentTier (id,step_number,title,description,note,payment_methods,scope_exclusions_note,created_date,updated_date) VALUES ('6a2f90b4f4b9cfa834d1a40b',3,'Production Deposit','50% of the total estimate, collected at contract sign-off. This initiates the engineering and manufacturing process for your project.','Collected at contract sign-off','["Check payable to Dream Home Design LLC","ACH / Bank Transfer","Zelle","Credit Card (3% processing fee applies)"]','Scope exclusions: Structural, electrical, and plumbing work is handled by outside specialists and contracted separately. We coordinate with these partners as part of your project management.','2026-06-15T05:42:12.069000','2026-06-15T05:42:12.069000');
INSERT OR REPLACE INTO InvestmentTier (id,step_number,title,description,note,payment_methods,scope_exclusions_note,created_date,updated_date) VALUES ('6a2f90b4f4b9cfa834d1a409',1,'Preliminary Estimate','Based on your initial consultation and project scope, we provide a preliminary estimate to help you understand the investment range for your project.','No commitment required','[]',NULL,'2026-06-15T05:42:12.069000','2026-06-15T05:42:12.069000');
INSERT OR REPLACE INTO InvestmentTier (id,step_number,title,description,note,payment_methods,scope_exclusions_note,created_date,updated_date) VALUES ('6a2f90b4f4b9cfa834d1a40a',2,'Retainer + Drawing Fee','5–10% of the preliminary estimate, collected to secure your place in our design queue. This fee is non-refundable but is applied toward your final purchase if the project proceeds.','Applied to final purchase','[]',NULL,'2026-06-15T05:42:12.069000','2026-06-15T05:42:12.069000');

-- Testimonial (3)
INSERT OR REPLACE INTO Testimonial (id,client_name,quote,rating,project_type,featured,created_date,updated_date) VALUES ('6a0c9aeb972c40dc9ebe5d5a','The Martinez Family','Dream Home Design transformed our kitchen into something we never imagined possible. The attention to detail and quality of craftsmanship is beyond anything we''ve seen.',5,'Kitchen',1,'2026-05-19T17:16:27.558000','2026-05-19T17:16:27.558000');
INSERT OR REPLACE INTO Testimonial (id,client_name,quote,rating,project_type,featured,created_date,updated_date) VALUES ('6a0c9aeb972c40dc9ebe5d5b','David & Lauren Chen','From the first consultation to the final walkthrough, the entire Dream Home team was exceptional. Our bathroom is now the highlight of our home.',5,'Bathroom',1,'2026-05-19T17:16:27.558000','2026-05-19T17:16:27.558000');
INSERT OR REPLACE INTO Testimonial (id,client_name,quote,rating,project_type,featured,created_date,updated_date) VALUES ('6a0c9aeb972c40dc9ebe5d5c','The Andersons','We''ve worked with other cabinet companies before, but Dream Home Design is in a completely different league. The custom pantry and home bar they built for us are works of art.',5,'Pantry & Home Bar',1,'2026-05-19T17:16:27.558000','2026-05-19T17:16:27.558000');

